/* Zukko — rus va ingliz tarjimalari (avtomatik yaratilgan) */
window.TARJIMA = Object.assign(window.TARJIMA||{}, {"Salom, do'stim! Men Zukko! Bugun biz sezgi a'zolarimiz bilan tanishamiz. Ular bizga olamni bilishga yordam beradi!":{"ru":"Привет, дружок! Я Зукко! Сегодня мы познакомимся с органами чувств. Они помогают нам узнавать мир!","en":"Hi, friend! I'm Zukko! Today we'll get to know our sense organs. They help us learn about the world!"},"Bizning sezgi a'zolarimiz":{"ru":"Наши органы чувств","en":"Our sense organs"},"Har bir kartochkani bosing va tinglang!":{"ru":"Нажми на каждую карточку и послушай!","en":"Tap each card and listen!"},"Ko'z":{"ru":"Глаз","en":"Eye"},"Ko'z bilan rang, shakl va o'lchamni ko'ramiz.":{"ru":"Глазами мы видим цвет, форму и размер.","en":"With our eyes we see color, shape and size."},"Quloq":{"ru":"Ухо","en":"Ear"},"Quloq bilan tovushlarni eshitamiz.":{"ru":"Ушами мы слышим звуки.","en":"With our ears we hear sounds."},"Burun":{"ru":"Нос","en":"Nose"},"Burun bilan hidlarni sezamiz.":{"ru":"Носом мы чувствуем запахи.","en":"With our nose we smell smells."},"Til":{"ru":"Язык","en":"Tongue"},"Til bilan shirin, nordon, sho'r va achchiq ta'mlarni bilamiz.":{"ru":"Языком мы узнаём сладкий, кислый, солёный и горький вкус.","en":"With our tongue we know sweet, sour, salty and bitter tastes."},"Qo'l (teri)":{"ru":"Рука (кожа)","en":"Hand (skin)"},"Teri bilan issiq, sovuq, yumshoq va qattiqni sezamiz.":{"ru":"Кожей мы чувствуем горячее, холодное, мягкое и твёрдое.","en":"With our skin we feel hot, cold, soft and hard."},"Avval buyumni bos, keyin uni sezadigan a'zoni bos!":{"ru":"Сначала нажми на предмет, потом на орган, который его чувствует!","en":"First tap the object, then tap the organ that senses it!"},"Kamalak":{"ru":"Радуга","en":"Rainbow"},"Musiqa":{"ru":"Музыка","en":"Music"},"Gul":{"ru":"Цветок","en":"Flower"},"Limon":{"ru":"Лимон","en":"Lemon"},"Muz":{"ru":"Лёд","en":"Ice"},"Qo'l":{"ru":"Рука","en":"Hand"},"Gulning hidini qaysi a'zo bilan sezamiz?":{"ru":"Каким органом мы чувствуем запах цветка?","en":"With which organ do we smell the flower?"},"Qo'shiqni qaysi a'zo bilan eshitamiz?":{"ru":"Каким органом мы слышим песню?","en":"With which organ do we hear a song?"},"Limon nordonligini qaysi a'zo bilan bilamiz?":{"ru":"Каким органом мы узнаём кислоту лимона?","en":"With which organ do we know the sourness of a lemon?"},"Kamalak ranglarini qaysi a'zo bilan ko'ramiz?":{"ru":"Каким органом мы видим цвета радуги?","en":"With which organ do we see the colors of the rainbow?"},"Muzning sovuqligini qaysi a'zo bilan sezamiz?":{"ru":"Каким органом мы чувствуем холод льда?","en":"With which organ do we feel the cold of ice?"},"Qaysi biri sezgi a'zosi emas?":{"ru":"Что из этого не орган чувств?","en":"Which one is not a sense organ?"},"Olma — sezgi a'zosi emas, u meva!":{"ru":"Яблоко — не орган чувств, это фрукт!","en":"An apple is not a sense organ, it's a fruit!"},"Qaysi biri tovush chiqarmaydi?":{"ru":"Что из этого не издаёт звука?","en":"Which one does not make a sound?"},"Gul tovush chiqarmaydi, uni hidlaymiz!":{"ru":"Цветок не издаёт звука, его мы нюхаем!","en":"A flower makes no sound, we smell it!"},"Qaysi birining ta'mini bilib bo'lmaydi?":{"ru":"Что из этого нельзя попробовать на вкус?","en":"Which one can't be tasted?"},"Qo'ng'iroqni yemaymiz, uni eshitamiz!":{"ru":"Колокольчик мы не едим, мы его слушаем!","en":"We don't eat a bell, we hear it!"},"Salom, do'stim! Men Zukko. Bugun ko'zlarimiz bilan nimalarni ko'rishimizni birga o'rganamiz!":{"ru":"Привет, дружок! Я Зукко. Сегодня вместе узнаем, что мы видим глазами!","en":"Hi, friend! I'm Zukko. Today we'll learn together what we see with our eyes!"},"Biz nimalarni ko'ramiz?":{"ru":"Что мы видим?","en":"What do we see?"},"Rang":{"ru":"Цвет","en":"Colour"},"Ko'zimiz bilan ranglarni ko'ramiz.":{"ru":"Глазами мы видим цвета.","en":"With our eyes we see colors."},"Shakl":{"ru":"Форма","en":"Shape"},"Buyumlarning shaklini ko'zimiz ko'radi.":{"ru":"Форму предметов видят наши глаза.","en":"Our eyes see the shape of objects."},"O'lcham":{"ru":"Размер","en":"Size"},"Kattami yoki kichikmi — ko'zimiz bilan bilamiz.":{"ru":"Большой или маленький — узнаём глазами.","en":"Big or small — we find out with our eyes."},"Harakat":{"ru":"Движение","en":"Movement"},"Kim yugurayotganini ko'zimiz ko'radi.":{"ru":"Кто бежит — видят наши глаза.","en":"Our eyes see who is running."},"Yorug'lik":{"ru":"Свет","en":"Light"},"Yorug'lik va qorong'ulikni ko'zimiz sezadi.":{"ru":"Свет и темноту чувствуют наши глаза.","en":"Our eyes sense light and darkness."},"Kamalak rangini qaysi a'zo bilan ko'ramiz?":{"ru":"Каким органом мы видим цвет радуги?","en":"With which organ do we see the color of the rainbow?"},"Buyumning shaklini qaysi a'zo ko'radi?":{"ru":"Какой орган видит форму предмета?","en":"Which organ sees the shape of an object?"},"Yorug'likni qaysi a'zo bilan sezamiz?":{"ru":"Каким органом мы чувствуем свет?","en":"With which organ do we sense light?"},"Qaysi birini ko'zimiz bilan ko'ra olmaymiz?":{"ru":"Что из этого мы не можем увидеть глазами?","en":"Which one can't we see with our eyes?"},"Tovushni ko'ra olmaymiz, uni quloq bilan eshitamiz!":{"ru":"Звук мы не видим, его мы слышим ушами!","en":"We can't see sound, we hear it with our ears!"},"Qaysi birini ko'z bilan emas, boshqa a'zo bilan sezamiz?":{"ru":"Что мы чувствуем не глазами, а другим органом?","en":"Which one do we sense not with eyes, but with another organ?"},"Muzqaymoq ta'mini til bilan tatib bilamiz!":{"ru":"Вкус мороженого мы узнаём языком!","en":"We taste ice cream with our tongue!"},"Salom! Men Zukko. Bugun ranglar va shakllar dunyosiga sayohat qilamiz!":{"ru":"Привет! Я Зукко. Сегодня отправимся в мир цветов и форм!","en":"Hi! I'm Zukko. Today we'll travel into the world of colors and shapes!"},"Rang va shakl":{"ru":"Цвет и форма","en":"Color and shape"},"Qizil":{"ru":"Красный","en":"Red"},"Qizil rang — olma va pomidor rangi.":{"ru":"Красный цвет — цвет яблока и помидора.","en":"Red is the color of an apple and a tomato."},"Ko'k":{"ru":"Синий","en":"Blue"},"Ko'k rang — osmon va dengiz rangi.":{"ru":"Синий цвет — цвет неба и моря.","en":"Blue is the color of the sky and the sea."},"Sariq":{"ru":"Жёлтый","en":"Yellow"},"Sariq rang — quyosh va limon rangi.":{"ru":"Жёлтый цвет — цвет солнца и лимона.","en":"Yellow is the color of the sun and a lemon."},"Yashil":{"ru":"Зелёный","en":"Green"},"Yashil rang — o't va barg rangi.":{"ru":"Зелёный цвет — цвет травы и листа.","en":"Green is the color of grass and a leaf."},"Doira":{"ru":"Круг","en":"Circle"},"Doira — dumaloq shakl, to'p kabi.":{"ru":"Круг — круглая форма, как мячик.","en":"A circle is a round shape, like a ball."},"Kvadrat":{"ru":"Квадрат","en":"Square"},"Kvadratning to'rt tomoni teng.":{"ru":"У квадрата все четыре стороны равны.","en":"A square has four equal sides."},"Uchburchak":{"ru":"Треугольник","en":"Triangle"},"Uchburchakning uchta burchagi bor.":{"ru":"У треугольника три угла.","en":"A triangle has three corners."},"Avval yuqoridan birini bos, keyin uning juftini bos!":{"ru":"Сначала нажми одну сверху, потом её пару!","en":"First tap one from the top, then tap its pair!"},"Apelsin":{"ru":"Апельсин","en":"Orange"},"Televizor":{"ru":"Телевизор","en":"TV"},"Pitsa bo'lagi":{"ru":"Кусочек пиццы","en":"Slice of pizza"},"Qizil olma":{"ru":"Красное яблоко","en":"Red apple"},"Qizil rang":{"ru":"Красный цвет","en":"Red color"},"Qaysi rang boshqalardan farq qiladi?":{"ru":"Какой цвет отличается от других?","en":"Which color is different from the others?"},"Ko'k rang ortiqcha, qolganlari qizil!":{"ru":"Синий цвет лишний, остальные красные!","en":"Blue is the odd one out, the rest are red!"},"Qaysi shakl dumaloq emas?":{"ru":"Какая форма не круглая?","en":"Which shape is not round?"},"Uchburchak dumaloq emas, qolganlari doira!":{"ru":"Треугольник не круглый, остальные круги!","en":"The triangle is not round, the rest are circles!"},"Salom, do'stim! Men Zukko. Quloqlarimiz bilan qanday tovushlarni eshitishimizni o'rganamiz!":{"ru":"Привет, дружок! Я Зукко. Узнаем, какие звуки мы слышим ушами!","en":"Hi, friend! I'm Zukko. Let's learn what sounds we hear with our ears!"},"Biz nimalarni eshitamiz?":{"ru":"Что мы слышим?","en":"What do we hear?"},"Quloq bilan barcha tovushlarni eshitamiz.":{"ru":"Ушами мы слышим все звуки.","en":"With our ears we hear all sounds."},"Baland tovush":{"ru":"Громкий звук","en":"Loud sound"},"Baland tovush kuchli eshitiladi.":{"ru":"Громкий звук слышно сильно.","en":"A loud sound is heard strongly."},"Past tovush":{"ru":"Тихий звук","en":"Quiet sound"},"Past tovush sekin eshitiladi.":{"ru":"Тихий звук слышно слабо.","en":"A quiet sound is heard softly."},"Yoqimli musiqani quloq bilan tinglaymiz.":{"ru":"Приятную музыку мы слушаем ушами.","en":"We listen to nice music with our ears."},"Qush ovozi":{"ru":"Голос птицы","en":"Bird's voice"},"Qushlarning sayrashini eshitamiz.":{"ru":"Мы слышим, как поют птицы.","en":"We hear the birds singing."},"Mushuk":{"ru":"Кошка","en":"Cat"},"Miyov":{"ru":"Мяу","en":"Meow"},"Kuchuk":{"ru":"Щенок","en":"Puppy"},"Vov-vov":{"ru":"Гав-гав","en":"Woof-woof"},"Qush":{"ru":"Птица","en":"Bird"},"Chirq-chirq":{"ru":"Чирик-чирик","en":"Tweet-tweet"},"Sher":{"ru":"Лев","en":"Lion"},"Boldiragan":{"ru":"Рычание","en":"Roar"},"Sher qanday tovush chiqaradi?":{"ru":"Какой звук издаёт лев?","en":"What sound does a lion make?"},"Baland":{"ru":"Громкий","en":"Loud"},"Past":{"ru":"Низ","en":"Down"},"Ovozsiz":{"ru":"Беззвучный","en":"Silent"},"Sichqoncha qanday tovush chiqaradi?":{"ru":"Какой звук издаёт мышка?","en":"What sound does a mouse make?"},"Juda baland":{"ru":"Очень громкий","en":"Very loud"},"Tovushni qaysi a'zo bilan eshitamiz?":{"ru":"Каким органом мы слышим звук?","en":"With which organ do we hear sound?"},"Gul tovush chiqarmaydi!":{"ru":"Цветок не издаёт звука!","en":"A flower makes no sound!"},"Qaysi birini eshita olmaymiz?":{"ru":"Что из этого мы не можем услышать?","en":"Which one can't we hear?"},"Rasm ovoz chiqarmaydi, uni faqat ko'ramiz!":{"ru":"Картинка не издаёт звука, мы её только видим!","en":"A picture makes no sound, we only see it!"},"Salom! Men Zukko. Burnimiz bilan qanday hidlarni sezishimizni birga o'rganamiz!":{"ru":"Привет! Я Зукко. Вместе узнаем, какие запахи мы чувствуем носом!","en":"Hi! I'm Zukko. Let's learn together what smells we sense with our nose!"},"Bular qanday hid taratadi?":{"ru":"Какой запах они издают?","en":"What smell do these give off?"},"Atirgul":{"ru":"Роза","en":"Rose"},"Atirgul yoqimli hid taratadi.":{"ru":"Роза издаёт приятный запах.","en":"A rose gives off a pleasant smell."},"Non":{"ru":"Хлеб","en":"Bread"},"Yangi non mazali hid taratadi.":{"ru":"Свежий хлеб издаёт вкусный запах.","en":"Fresh bread gives off a tasty smell."},"Sarimsoq":{"ru":"Чеснок","en":"Garlic"},"Sarimsoq o'tkir hid taratadi.":{"ru":"Чеснок издаёт резкий запах.","en":"Garlic gives off a sharp smell."},"Axlat":{"ru":"Мусор","en":"Trash"},"Axlat yoqimsiz hid taratadi.":{"ru":"Мусор издаёт неприятный запах.","en":"Trash gives off an unpleasant smell."},"To'g'ri! Atirgul juda yoqimli hidlaydi.":{"ru":"Верно! Роза пахнет очень приятно.","en":"Correct! A rose smells very nice."},"Hidni ko'zimiz bilan sezamiz.":{"ru":"Запах мы чувствуем глазами.","en":"We sense smell with our eyes."},"Yo'q! Hidni burun bilan sezamiz.":{"ru":"Нет! Запах мы чувствуем носом.","en":"No! We sense smell with our nose."},"Limon yangi va yoqimli hid taratadi.":{"ru":"Лимон издаёт свежий и приятный запах.","en":"A lemon gives off a fresh and pleasant smell."},"To'g'ri! Limon xushbo'y hidlaydi.":{"ru":"Верно! Лимон пахнет ароматно.","en":"Correct! A lemon smells fragrant."},"Axlat yoqimli hid taratadi.":{"ru":"Мусор издаёт приятный запах.","en":"Trash gives off a pleasant smell."},"Yo'q! Axlat yoqimsiz hid taratadi.":{"ru":"Нет! Мусор издаёт неприятный запах.","en":"No! Trash gives off an unpleasant smell."},"Qaysi birining hidi yo'q?":{"ru":"У чего из этого нет запаха?","en":"Which one has no smell?"},"Tosh hid taratmaydi!":{"ru":"Камень не издаёт запаха!","en":"A stone gives off no smell!"},"Qaysi birini hidlamaymiz, balki eshitamiz?":{"ru":"Что мы не нюхаем, а слышим?","en":"Which one do we not smell, but hear?"},"Qo'ng'iroqni hidlamaymiz, uning ovozini eshitamiz!":{"ru":"Колокольчик мы не нюхаем, мы слышим его звон!","en":"We don't smell a bell, we hear its sound!"},"Salom, do'stim! Men Zukko. Tilimiz bilan qanday ta'mlarni sezishimizni o'rganamiz!":{"ru":"Привет, дружок! Я Зукко. Узнаем, какие вкусы мы чувствуем языком!","en":"Hi, friend! I'm Zukko. Let's learn what tastes we sense with our tongue!"},"Turli xil ta'mlar":{"ru":"Разные вкусы","en":"Different tastes"},"Shirin":{"ru":"Сладкий","en":"Sweet"},"Asal va shakar shirin bo'ladi.":{"ru":"Мёд и сахар сладкие.","en":"Honey and sugar are sweet."},"Nordon":{"ru":"Кислый","en":"Sour"},"Limon nordon ta'mga ega.":{"ru":"У лимона кислый вкус.","en":"A lemon has a sour taste."},"Sho'r":{"ru":"Солёный","en":"Salty"},"Tuz taomni sho'r qiladi.":{"ru":"Соль делает еду солёной.","en":"Salt makes food salty."},"Achchiq":{"ru":"Горький","en":"Bitter"},"Qalampir achchiq ta'mli bo'ladi.":{"ru":"У перца горький вкус.","en":"Pepper has a bitter taste."},"Konfet":{"ru":"Конфета","en":"Candy"},"Tuzli kraker":{"ru":"Солёный крекер","en":"Salty cracker"},"Qalampir":{"ru":"Перец","en":"Pepper"},"Shokolad qanday ta'mga ega?":{"ru":"Какой вкус у шоколада?","en":"What taste does chocolate have?"},"Limon qanday ta'mli?":{"ru":"Какой на вкус лимон?","en":"What does a lemon taste like?"},"Ta'mni qaysi a'zo bilan sezamiz?":{"ru":"Каким органом мы чувствуем вкус?","en":"With which organ do we sense taste?"},"Salom! Men Zukko. Terimiz bilan issiq, sovuq, yumshoq va qattiqni qanday sezishimizni o'rganamiz!":{"ru":"Привет! Я Зукко. Узнаем, как кожей мы чувствуем горячее, холодное, мягкое и твёрдое!","en":"Hi! I'm Zukko. Let's learn how we feel hot, cold, soft and hard with our skin!"},"Bizning his-tuyg'ularimiz":{"ru":"Наши ощущения","en":"Our feelings"},"Qo'l va teri bilan buyumlarni ushlab sezamiz.":{"ru":"Рукой и кожей мы чувствуем предметы на ощупь.","en":"With our hand and skin we feel objects by touch."},"Issiq":{"ru":"Горячий","en":"Hot"},"Olov va choy issiq bo'ladi.":{"ru":"Огонь и чай горячие.","en":"Fire and tea are hot."},"Sovuq":{"ru":"Холодный","en":"Cold"},"Muz va qor sovuq bo'ladi.":{"ru":"Лёд и снег холодные.","en":"Ice and snow are cold."},"Yumshoq":{"ru":"Мягкий","en":"Soft"},"O'yinchoq ayiq yumshoq va mayin.":{"ru":"Игрушечный мишка мягкий и нежный.","en":"A toy bear is soft and gentle."},"Qattiq":{"ru":"Твёрдый","en":"Hard"},"Tosh qattiq bo'ladi.":{"ru":"Камень твёрдый.","en":"A stone is hard."},"Muzga tegsangiz nimani his qilasiz?":{"ru":"Что ты почувствуешь, если коснёшься льда?","en":"What do you feel when you touch ice?"},"Olovga yaqinlashsangiz nimani his qilasiz?":{"ru":"Что ты почувствуешь, если приблизишься к огню?","en":"What do you feel when you come near fire?"},"O'yinchoq ayiq qanday seziladi?":{"ru":"Каким на ощупь кажется игрушечный мишка?","en":"How does a toy bear feel?"},"Qaysi biri sovuq emas?":{"ru":"Что из этого не холодное?","en":"Which one is not cold?"},"Olov issiq, qolganlari sovuq!":{"ru":"Огонь горячий, остальные холодные!","en":"Fire is hot, the rest are cold!"},"Qaysi biri yumshoq emas?":{"ru":"Что из этого не мягкое?","en":"Which one is not soft?"},"Tosh qattiq, qolganlari yumshoq!":{"ru":"Камень твёрдый, остальные мягкие!","en":"A stone is hard, the rest are soft!"},"Salom, do'stim! Men Zukko. Bugun bitta olmani beshta sezgimiz bilan tekshiramiz!":{"ru":"Привет, дружок! Я Зукко. Сегодня проверим одно яблоко всеми пятью чувствами!","en":"Hi, friend! I'm Zukko. Today we'll explore one apple with all five senses!"},"Buyumlarga ta'rif beramiz":{"ru":"Описываем предметы","en":"We describe objects"},"Ko'ramiz":{"ru":"Видим","en":"We see"},"Olma qizil ekanini ko'zimiz ko'radi.":{"ru":"Что яблоко красное, видят наши глаза.","en":"Our eyes see that the apple is red."},"Hidlaymiz":{"ru":"Нюхаем","en":"We smell"},"Olmaning yoqimli hidini burun sezadi.":{"ru":"Приятный запах яблока чувствует нос.","en":"The nose senses the apple's pleasant smell."},"Tatib ko'ramiz":{"ru":"Пробуем на вкус","en":"We taste"},"Olma shirin ekanini til biladi.":{"ru":"Что яблоко сладкое, знает язык.","en":"The tongue knows that the apple is sweet."},"Ushlaymiz":{"ru":"Трогаем","en":"We touch"},"Olma silliq ekanini qo'l sezadi.":{"ru":"Что яблоко гладкое, чувствует рука.","en":"The hand feels that the apple is smooth."},"Eshitamiz":{"ru":"Слышим","en":"We hear"},"Olmani tishlaganda qars-qurs ovoz eshitamiz.":{"ru":"Когда кусаем яблоко, слышим хрустящий звук.","en":"When we bite the apple, we hear a crunchy sound."},"Yoqimli hid":{"ru":"Приятный запах","en":"Pleasant smell"},"Shirin ta'm":{"ru":"Сладкий вкус","en":"Sweet taste"},"Silliq yuza":{"ru":"Гладкая поверхность","en":"Smooth surface"},"Olmaning qizil rangini qaysi a'zo biladi?":{"ru":"Какой орган узнаёт красный цвет яблока?","en":"Which organ knows the red color of the apple?"},"Olma shirin ekanini qaysi a'zo sezadi?":{"ru":"Какой орган чувствует, что яблоко сладкое?","en":"Which organ senses that the apple is sweet?"},"Olmaning yoqimli hidini qaysi a'zo sezadi?":{"ru":"Какой орган чувствует приятный запах яблока?","en":"Which organ senses the apple's pleasant smell?"},"Salom, aziz do'stim! Men Zukko. Endi beshta sezgimizni birga takrorlaymiz. Biz olamni sezgilarimiz bilan qabul qilamiz!":{"ru":"Привет, милый дружок! Я Зукко. Теперь вместе повторим все пять чувств. Мы воспринимаем мир своими чувствами!","en":"Hi, dear friend! I'm Zukko. Now let's review all five senses together. We perceive the world with our senses!"},"Bizning dunyoqarashimiz":{"ru":"Как мы познаём мир","en":"How we see the world"},"Ko'z bilan rang, shakl va harakatni ko'ramiz.":{"ru":"Глазами мы видим цвет, форму и движение.","en":"With our eyes we see color, shape and movement."},"Til bilan ta'mni sezamiz.":{"ru":"Языком мы чувствуем вкус.","en":"With our tongue we sense taste."},"Teri":{"ru":"Кожа","en":"Skin"},"Teri bilan issiq, sovuq va yumshoqni sezamiz.":{"ru":"Кожей мы чувствуем горячее, холодное и мягкое.","en":"With our skin we feel hot, cold and soft."},"Musiqani qaysi a'zo bilan eshitamiz?":{"ru":"Каким органом мы слышим музыку?","en":"With which organ do we hear music?"},"Asalning shirin ta'mini qaysi a'zo sezadi?":{"ru":"Какой орган чувствует сладкий вкус мёда?","en":"Which organ senses the sweet taste of honey?"},"Muzning sovuqligini qaysi a'zo sezadi?":{"ru":"Какой орган чувствует холод льда?","en":"Which organ senses the cold of ice?"},"Ranglarni ko'z bilan ko'ramiz.":{"ru":"Цвета мы видим глазами.","en":"We see colors with our eyes."},"To'g'ri! Ko'z ranglarni ko'radi.":{"ru":"Верно! Глаз видит цвета.","en":"Correct! The eye sees colors."},"Hidni quloq bilan sezamiz.":{"ru":"Запах мы чувствуем ушами.","en":"We sense smell with our ears."},"Ta'mni til bilan sezamiz.":{"ru":"Вкус мы чувствуем языком.","en":"We sense taste with our tongue."},"To'g'ri! Til ta'mni sezadi.":{"ru":"Верно! Язык чувствует вкус.","en":"Correct! The tongue senses taste."},"Issiq va sovuqni teri bilan sezamiz.":{"ru":"Горячее и холодное мы чувствуем кожей.","en":"We feel hot and cold with our skin."},"To'g'ri! Teri issiq va sovuqni sezadi.":{"ru":"Верно! Кожа чувствует горячее и холодное.","en":"Correct! The skin senses hot and cold."},"Tovushni burun bilan eshitamiz.":{"ru":"Звук мы слышим носом.","en":"We hear sound with our nose."},"Yo'q! Tovushni quloq bilan eshitamiz.":{"ru":"Нет! Звук мы слышим ушами.","en":"No! We hear sound with our ears."},"Salom, do'stim! Men Zukkoman. Bugun ketma-ketlik nima ekanini o'rganamiz. Har narsaning boshi, o'rtasi va oxiri bor!":{"ru":"Привет, дружок! Я Зукко. Сегодня мы узнаем, что такое последовательность. У всего есть начало, середина и конец!","en":"Hi, friend! I'm Zukko. Today we'll learn what a sequence is. Everything has a beginning, a middle and an end!"},"Ketma-ketlik":{"ru":"Последовательность","en":"Sequence"},"Birinchi":{"ru":"Первый","en":"First"},"Ketma-ketlik birinchidan boshlanadi.":{"ru":"Последовательность начинается с первого.","en":"A sequence starts with the first one."},"Keyin":{"ru":"Потом","en":"Next"},"Birinchidan keyin ikkinchisi keladi.":{"ru":"После первого идёт второй.","en":"After the first comes the second."},"Uchinchi":{"ru":"Третий","en":"Third"},"Keyin uchinchisi keladi.":{"ru":"Потом идёт третий.","en":"Then comes the third."},"Oxiri":{"ru":"Конец","en":"The end"},"Eng oxirida ketma-ketlik tugaydi.":{"ru":"В самом конце последовательность заканчивается.","en":"At the very end the sequence finishes."},"Ertalab nima birinchi bo'ladi? Boshidan bosing!":{"ru":"Что бывает утром первым? Нажимай по порядку!","en":"What comes first in the morning? Tap from the start!"},"Uyg'onish":{"ru":"Просыпаться","en":"Waking up"},"Kiyinish":{"ru":"Одеваться","en":"Getting dressed"},"Nonushta":{"ru":"Завтрак","en":"Breakfast"},"Maktab":{"ru":"Школа","en":"School"},"Kun birinchi navbatda nima bilan boshlanadi?":{"ru":"С чего в первую очередь начинается день?","en":"What does the day start with first?"},"Uyg'ongandan keyin nima qilamiz?":{"ru":"Что мы делаем после того, как проснулись?","en":"What do we do after waking up?"},"Uxlash":{"ru":"Спать","en":"Sleeping"},"Ikkidan keyin qaysi raqam keladi?":{"ru":"Какое число идёт после двух?","en":"Which number comes after two?"},"Bir":{"ru":"Один","en":"One"},"Uch":{"ru":"Три","en":"Three"},"Ikki":{"ru":"Два","en":"Two"},"Salom! Bu Zukko. Ba'zi narsalar oldin, ba'zilari keyin bo'ladi. Kel, fasllar bilan o'rganamiz!":{"ru":"Привет! Это Зукко. Одни вещи бывают раньше, другие позже. Давай учиться на временах года!","en":"Hi! It's Zukko. Some things come before, others after. Let's learn with the seasons!"},"Oldin — keyin":{"ru":"До — после","en":"Before — after"},"Oldin":{"ru":"До","en":"Before"},"Oldin — bu birinchi bo'lgan narsa.":{"ru":"«До» — это то, что было первым.","en":"\"Before\" is the thing that came first."},"Keyin — bu undan so'ng bo'ladigan narsa.":{"ru":"«После» — это то, что происходит потом.","en":"\"After\" is the thing that comes next."},"Bahor":{"ru":"Весна","en":"Spring"},"Bahordan keyin yoz keladi.":{"ru":"После весны приходит лето.","en":"After spring comes summer."},"Kuz":{"ru":"Осень","en":"Autumn"},"Kuzdan oldin yoz bo'ladi.":{"ru":"Перед осенью бывает лето.","en":"Before autumn comes summer."},"Fasllarni tartib bilan bosing. Bahordan boshlang!":{"ru":"Нажимай времена года по порядку. Начни с весны!","en":"Tap the seasons in order. Start with spring!"},"Yoz":{"ru":"Лето","en":"Summer"},"Qish":{"ru":"Зима","en":"Winter"},"Bahordan keyin qaysi fasl keladi?":{"ru":"Какое время года идёт после весны?","en":"Which season comes after spring?"},"Kuzdan oldin qaysi fasl bo'ladi?":{"ru":"Какое время года бывает перед осенью?","en":"Which season comes before autumn?"},"Qishdan keyin qaysi fasl keladi?":{"ru":"Какое время года идёт после зимы?","en":"Which season comes after winter?"},"Salom, do'stim! Zukko bu yerda. Ba'zi narsalar o'zgaradi: bug'doy edi, non bo'ldi! Kel, ko'ramiz.":{"ru":"Привет, дружок! Зукко здесь. Некоторые вещи меняются: была пшеница — стал хлеб! Давай посмотрим.","en":"Hi, friend! Zukko is here. Some things change: it was wheat, and it became bread! Let's take a look."},"Edi — bo'ldi":{"ru":"Было — стало","en":"Was — became"},"Bug'doy":{"ru":"Пшеница","en":"Wheat"},"Bug'doydan non tayyorlanadi.":{"ru":"Из пшеницы делают хлеб.","en":"Bread is made from wheat."},"Non bug'doydan bo'ldi.":{"ru":"Хлеб получился из пшеницы.","en":"Bread came from wheat."},"Olma":{"ru":"Яблоко","en":"Apple"},"Olmadan mazali sharbat bo'ladi.":{"ru":"Из яблока получается вкусный сок.","en":"Apple makes tasty juice."},"Sut":{"ru":"Молоко","en":"Milk"},"Sutni sigir beradi.":{"ru":"Молоко даёт корова.","en":"Milk comes from a cow."},"Sharbat":{"ru":"Сок","en":"Juice"},"Sigir":{"ru":"Корова","en":"Cow"},"Uzum":{"ru":"Виноград","en":"Grapes"},"Ichimlik":{"ru":"Напиток","en":"Drink"},"Non qanday tayyorlanadi? Boshidan bosing!":{"ru":"Как готовят хлеб? Нажимай по порядку!","en":"How is bread made? Tap from the start!"},"Un":{"ru":"Мука","en":"Flour"},"Xamir":{"ru":"Тесто","en":"Dough"},"Bug'doydan nima bo'ladi?":{"ru":"Что получается из пшеницы?","en":"What comes from wheat?"},"Olmadan nima tayyorlanadi?":{"ru":"Что делают из яблока?","en":"What is made from an apple?"},"Sigir bizga nima beradi?":{"ru":"Что нам даёт корова?","en":"What does a cow give us?"},"Salom! Men Zukko. Narsalar kichik yoki katta bo'ladi. Kel, kichigidan kattasiga tartib qilamiz!":{"ru":"Привет! Я Зукко. Вещи бывают маленькие и большие. Давай выстроим их от маленького к большому!","en":"Hi! I'm Zukko. Things can be small or big. Let's put them in order from small to big!"},"O'sish va kamayish tartibi":{"ru":"Порядок по возрастанию и убыванию","en":"Order by size, growing and shrinking"},"Chumoli":{"ru":"Муравей","en":"Ant"},"Chumoli juda kichkina.":{"ru":"Муравей совсем маленький.","en":"An ant is very tiny."},"It":{"ru":"Собака","en":"Dog"},"It chumolidan katta.":{"ru":"Собака больше муравья.","en":"A dog is bigger than an ant."},"Fil":{"ru":"Слон","en":"Elephant"},"Fil juda katta hayvon.":{"ru":"Слон — очень большое животное.","en":"An elephant is a very big animal."},"Kit":{"ru":"Кит","en":"Whale"},"Kit eng katta hayvon.":{"ru":"Кит — самое большое животное.","en":"A whale is the biggest animal."},"Eng kichigidan boshlab bosing!":{"ru":"Нажимай, начиная с самого маленького!","en":"Tap starting from the smallest!"},"Endi eng kattadan boshlab bosing!":{"ru":"Теперь нажимай, начиная с самого большого!","en":"Now tap starting from the biggest!"},"Daraxt":{"ru":"Дерево","en":"Tree"},"Nihol":{"ru":"Саженец","en":"Sapling"},"Maysa":{"ru":"Росток","en":"Sprout"},"Urug'":{"ru":"Семечко","en":"Seed"},"Qaysi biri eng kichik?":{"ru":"Какой из них самый маленький?","en":"Which one is the smallest?"},"Qaysi biri eng katta?":{"ru":"Какой из них самый большой?","en":"Which one is the biggest?"},"Urug'dan keyin nima o'sadi?":{"ru":"Что вырастает после семечка?","en":"What grows after a seed?"},"Salom, do'stim! Zukko bu yerda. Ish qilishda tartib muhim. Choy damlash yoki kiyinishni to'g'ri tartibda qilamiz!":{"ru":"Привет, дружок! Зукко здесь. В любом деле важен порядок. Заварим чай или оденемся в правильном порядке!","en":"Hi, friend! Zukko is here. In every task the order matters. Let's make tea or get dressed in the right order!"},"Amallarning ketma-ketligi":{"ru":"Последовательность действий","en":"Order of steps"},"Tartib":{"ru":"Порядок","en":"Order"},"Har bir ishning o'z tartibi bor.":{"ru":"У каждого дела свой порядок.","en":"Every task has its own order."},"Birinchi qadam":{"ru":"Первый шаг","en":"First step"},"Avval birinchi qadamni bajaramiz.":{"ru":"Сначала делаем первый шаг.","en":"First we do the first step."},"So'ng keyingi qadamga o'tamiz.":{"ru":"Потом переходим к следующему шагу.","en":"Then we move to the next step."},"Tayyor":{"ru":"Готово","en":"Done"},"Hamma qadam bajarilsa, ish tayyor bo'ladi.":{"ru":"Когда все шаги сделаны, дело готово.","en":"When all the steps are done, the task is ready."},"Choyni qanday damlaymiz? Boshidan bosing!":{"ru":"Как мы завариваем чай? Нажимай по порядку!","en":"How do we make tea? Tap from the start!"},"Choynak":{"ru":"Чайник","en":"Teapot"},"Choy solish":{"ru":"Насыпать чай","en":"Add the tea"},"Suv quyish":{"ru":"Налить воду","en":"Pour the water"},"Qaynatish":{"ru":"Вскипятить","en":"Boil"},"Ichish":{"ru":"Пить","en":"Drink"},"To'g'ri tartibda kiyinamiz. Boshidan bosing!":{"ru":"Оденемся в правильном порядке. Нажимай по порядку!","en":"Let's get dressed in the right order. Tap from the start!"},"Paypoq":{"ru":"Носок","en":"Sock"},"Ko'ylak":{"ru":"Рубашка","en":"Shirt"},"Shim":{"ru":"Штаны","en":"Trousers"},"Poyabzal":{"ru":"Обувь","en":"Shoes"},"Choy damlashda birinchi nima kerak?":{"ru":"Что нужно первым, чтобы заварить чай?","en":"What do we need first to make tea?"},"Poyabzaldan oldin nimani kiyamiz?":{"ru":"Что мы надеваем перед обувью?","en":"What do we put on before shoes?"},"Shapka":{"ru":"Шапка","en":"Hat"},"Qo'lqop":{"ru":"Варежки","en":"Mittens"},"Suvni qanday qilamiz?":{"ru":"Что мы делаем с водой?","en":"What do we do with the water?"},"Muzlatamiz":{"ru":"Замораживаем","en":"Freeze it"},"Qaynatamiz":{"ru":"Кипятим","en":"Boil it"},"Ekamiz":{"ru":"Сажаем","en":"Plant it"},"Salom! Men Zukko. Tabiatda ba'zi narsalar qayta-qayta takrorlanadi. Kunduz keladi, tun keladi, yana kunduz!":{"ru":"Привет! Я Зукко. В природе некоторые вещи повторяются снова и снова. Приходит день, приходит ночь и снова день!","en":"Hi! I'm Zukko. In nature some things repeat again and again. Day comes, night comes, and day again!"},"Tabiatdagi takrorlanish hodisalari":{"ru":"Повторяющиеся явления в природе","en":"Repeating events in nature"},"Takrorlanish":{"ru":"Повторение","en":"Repetition"},"Ba'zi hodisalar qayta-qayta bo'ladi.":{"ru":"Некоторые явления случаются снова и снова.","en":"Some events happen again and again."},"Kunduz":{"ru":"День","en":"Day"},"Har kuni quyosh chiqadi.":{"ru":"Каждый день восходит солнце.","en":"Every day the sun rises."},"Tun":{"ru":"Ночь","en":"Night"},"Har kechada oy chiqadi.":{"ru":"Каждую ночь восходит луна.","en":"Every night the moon rises."},"Fasllar":{"ru":"Времена года","en":"Seasons"},"Fasllar har yili takrorlanadi.":{"ru":"Времена года повторяются каждый год.","en":"The seasons repeat every year."},"Kun qanday o'tadi? Ertalabdan boshlang!":{"ru":"Как проходит день? Начни с утра!","en":"How does the day go? Start from the morning!"},"Tong":{"ru":"Утро","en":"Morning"},"Kechqurun":{"ru":"Вечер","en":"Evening"},"Tundan keyin nima keladi?":{"ru":"Что приходит после ночи?","en":"What comes after night?"},"Yana tun":{"ru":"Снова ночь","en":"Night again"},"Qaysi biri har kuni takrorlanadi?":{"ru":"Что из этого повторяется каждый день?","en":"Which of these repeats every day?"},"Tug'ilgan kun":{"ru":"День рождения","en":"Birthday"},"Quyosh chiqishi":{"ru":"Восход солнца","en":"Sunrise"},"Sovg'a":{"ru":"Подарок","en":"Gift"},"Har yili nima takrorlanadi?":{"ru":"Что повторяется каждый год?","en":"What repeats every year?"},"Mashina":{"ru":"Машина","en":"Car"},"Kitob":{"ru":"Книга","en":"Book"},"Qaysi biri takrorlanadigan tabiat hodisasi emas?":{"ru":"Что из этого не является повторяющимся явлением природы?","en":"Which of these is not a repeating event of nature?"},"Mashina tabiat hodisasi emas!":{"ru":"Машина — это не явление природы!","en":"A car is not a nature event!"},"Qaysi biri har kuni takrorlanmaydi?":{"ru":"Что из этого не повторяется каждый день?","en":"Which of these does not repeat every day?"},"Tug'ilgan kun har kuni bo'lmaydi!":{"ru":"День рождения бывает не каждый день!","en":"A birthday is not every day!"},"Salom, do'stim! Zukko bu yerda. Sog'lom bo'lish uchun tishni yuvamiz, yaxshi ovqatlanamiz va sport qilamiz!":{"ru":"Привет, дружок! Зукко здесь. Чтобы быть здоровым, мы чистим зубы, хорошо кушаем и занимаемся спортом!","en":"Hi, friend! Zukko is here. To stay healthy we brush our teeth, eat well and do sports!"},"Bizning sog'lom turmush tarzimiz":{"ru":"Наш здоровый образ жизни","en":"Our healthy way of life"},"Tish yuvish":{"ru":"Чистить зубы","en":"Brushing teeth"},"Har kuni tishni yuvamiz.":{"ru":"Каждый день мы чистим зубы.","en":"We brush our teeth every day."},"To'g'ri ovqat":{"ru":"Здоровая еда","en":"Healthy food"},"Meva va sabzavot yeymiz.":{"ru":"Мы едим фрукты и овощи.","en":"We eat fruit and vegetables."},"Uyqu":{"ru":"Сон","en":"Sleep"},"Yaxshi uxlash sog'liq uchun foydali.":{"ru":"Хороший сон полезен для здоровья.","en":"Good sleep is good for your health."},"Toza havo":{"ru":"Свежий воздух","en":"Fresh air"},"Ochiq havoda sayr qilamiz.":{"ru":"Мы гуляем на свежем воздухе.","en":"We walk in the fresh air."},"Sport":{"ru":"Спорт","en":"Sport"},"Harakat qilish tanani baquvvat qiladi.":{"ru":"Движение делает тело крепким.","en":"Moving makes the body strong."},"Ertalab nima qilamiz? Boshidan bosing!":{"ru":"Что мы делаем утром? Нажимай по порядку!","en":"What do we do in the morning? Tap from the start!"},"Yuvinish":{"ru":"Умываться","en":"Washing up"},"Mashq":{"ru":"Зарядка","en":"Exercise"},"Har kuni tishni yuvish kerak.":{"ru":"Зубы нужно чистить каждый день.","en":"We should brush our teeth every day."},"To'g'ri! Tishlar toza bo'ladi.":{"ru":"Верно! Зубы будут чистыми.","en":"Correct! The teeth will be clean."},"Ko'p shirinlik yeyish foydali.":{"ru":"Есть много сладкого полезно.","en":"Eating lots of sweets is good for you."},"Yo'q! Ko'p shirinlik zararli.":{"ru":"Нет! Много сладкого вредно.","en":"No! Too many sweets are harmful."},"Meva va sabzavot foydali.":{"ru":"Фрукты и овощи полезны.","en":"Fruit and vegetables are good for you."},"To'g'ri! Ular sog'liq beradi.":{"ru":"Верно! Они дают здоровье.","en":"Correct! They keep us healthy."},"Yaxshi uxlash kerak.":{"ru":"Нужно хорошо спать.","en":"We should sleep well."},"To'g'ri! Uyqu tanani tiklaydi.":{"ru":"Верно! Сон восстанавливает тело.","en":"Correct! Sleep restores the body."},"Qaysi biri sog'lom odat emas?":{"ru":"Что из этого не является здоровой привычкой?","en":"Which of these is not a healthy habit?"},"Ko'p shirinlik sog'lom odat emas!":{"ru":"Много сладкого — не здоровая привычка!","en":"Too many sweets is not a healthy habit!"},"Qaysi biri foydali emas?":{"ru":"Что из этого не полезно?","en":"Which of these is not good for you?"},"Zararli ovqat foydali emas!":{"ru":"Вредная еда не полезна!","en":"Junk food is not good for you!"},"Salom, do'stim! Men Zukko. Bugun tepa va past tomonlarni o'rganamiz. Yuqoriga va pastga qaraymiz!":{"ru":"Привет, дружок! Я Зукко. Сегодня учим верх и низ. Смотрим вверх и вниз!","en":"Hi, friend! I'm Zukko. Today we learn top and bottom. Let's look up and down!"},"Tepa — past":{"ru":"Верх — низ","en":"Top — bottom"},"Tepa":{"ru":"Верх","en":"Up"},"Tepa — yuqori tomon. Osmon tepada.":{"ru":"Верх — это где выше. Небо наверху.","en":"Top is the upper side. The sky is at the top."},"Past — quyi tomon. Yer pastda.":{"ru":"Низ — это где ниже. Земля внизу.","en":"Bottom is the lower side. The ground is at the bottom."},"O'rta":{"ru":"Середина","en":"Middle"},"O'rta — tepa bilan past orasida.":{"ru":"Середина — между верхом и низом.","en":"The middle is between top and bottom."},"Eng tepa":{"ru":"Самый верх","en":"Very top"},"Eng tepa — hammadan yuqori joy.":{"ru":"Самый верх — выше всех.","en":"The very top is the highest place of all."},"Eng past":{"ru":"Самый низ","en":"Very bottom"},"Eng past — hammadan quyi joy.":{"ru":"Самый низ — ниже всех.","en":"The very bottom is the lowest place of all."},"Eng baland":{"ru":"Самый высокий","en":"The tallest"},"Osmon tepada":{"ru":"Небо наверху","en":"The sky is at the top"},"Yer pastda":{"ru":"Земля внизу","en":"The ground is at the bottom"},"Quyosh tepada":{"ru":"Солнце наверху","en":"The sun is at the top"},"Oyoq pastda":{"ru":"Ноги внизу","en":"The feet are at the bottom"},"Javonning eng tepasida nima bo'ladi?":{"ru":"Что находится на самом верху полки?","en":"What is at the very top of the shelf?"},"Kitob tepada":{"ru":"Книга наверху","en":"The book is at the top"},"Oyoq kiyim":{"ru":"Обувь","en":"Shoes"},"Uyning tepasida nima bo'ladi?":{"ru":"Что находится наверху дома?","en":"What is at the top of the house?"},"Tom tepada":{"ru":"Крыша наверху","en":"The roof is at the top"},"Eshik":{"ru":"Дверь","en":"Door"},"Deraza":{"ru":"Окно","en":"Window"},"Daraxtning pastida nima bo'ladi?":{"ru":"Что находится внизу дерева?","en":"What is at the bottom of the tree?"},"Olma tepada":{"ru":"Яблоко наверху","en":"The apple is at the top"},"Ildiz pastda":{"ru":"Корни внизу","en":"The roots are at the bottom"},"Qush tepada":{"ru":"Птица наверху","en":"The bird is at the top"},"Binoning eng pastki qavatida nima bo'ladi?":{"ru":"Что находится на самом нижнем этаже здания?","en":"What is on the very bottom floor of the building?"},"Bulut tepada":{"ru":"Облако наверху","en":"The cloud is at the top"},"Kirish eshigi pastda":{"ru":"Входная дверь внизу","en":"The entrance door is at the bottom"},"Antenna tepada":{"ru":"Антенна наверху","en":"The antenna is at the top"},"Salom! Men Zukko. Bugun oldinda va orqada nima borligini o'rganamiz. Old tomon va orqa tomon!":{"ru":"Привет! Я Зукко. Сегодня узнаём, что спереди и что сзади. Перёд и зад!","en":"Hi! I'm Zukko. Today we learn what is in front and behind. Front side and back side!"},"Oldinda — orqada":{"ru":"Спереди — сзади","en":"In front — behind"},"Oldinda":{"ru":"Спереди","en":"In front"},"Oldinda — old tomon. Ko'zimiz oldga qaraydi.":{"ru":"Спереди — это перёд. Наши глаза смотрят вперёд.","en":"In front is the front side. Our eyes look forward."},"Orqada":{"ru":"Сзади","en":"Behind"},"Orqada — orqa tomon. Yelkamiz orqada.":{"ru":"Сзади — это зад. Наши плечи сзади.","en":"Behind is the back side. Our shoulders are behind."},"Old tomon":{"ru":"Перёд","en":"Front side"},"Yuzimiz qaragan tomon — old tomon.":{"ru":"Сторона, куда смотрит лицо, — это перёд.","en":"The side our face looks toward is the front."},"Orqa tomon":{"ru":"Зад","en":"Back side"},"Yelkamizdagi sumka orqa tomonda.":{"ru":"Рюкзак на плечах находится сзади.","en":"The bag on our shoulders is on the back side."},"Qizchaning orqasida nima bor?":{"ru":"Что находится за спиной у девочки?","en":"What is behind the girl?"},"Sumka orqada":{"ru":"Сумка сзади","en":"The bag is behind"},"Ko'z oldda":{"ru":"Глаза спереди","en":"The eyes are in front"},"Burun oldda":{"ru":"Нос спереди","en":"The nose is in front"},"Mashinaning oldida nima bo'ladi?":{"ru":"Что находится спереди у машины?","en":"What is at the front of the car?"},"Chiroq oldda":{"ru":"Фары спереди","en":"The headlights are in front"},"Sumka":{"ru":"Сумка","en":"Bag"},"Yuk orqada":{"ru":"Груз сзади","en":"The load is behind"},"Poyezdning eng oldida nima yuradi?":{"ru":"Что едет в самом начале поезда?","en":"What goes at the very front of the train?"},"Vagon orqada":{"ru":"Вагон сзади","en":"The carriage is behind"},"Lokomotiv oldda":{"ru":"Локомотив спереди","en":"The locomotive is in front"},"Temir yo'l":{"ru":"Железная дорога","en":"Railway"},"Bolaning yuzida nima oldda bo'ladi?":{"ru":"Что находится спереди на лице ребёнка?","en":"What is at the front of a child's face?"},"Soch orqada":{"ru":"Волосы сзади","en":"The hair is behind"},"Qaysi biri old tomonda emas?":{"ru":"Что из этого не спереди?","en":"Which one is not in front?"},"Sumka orqada bo'ladi, ko'z, burun va og'iz oldda!":{"ru":"Сумка сзади, а глаза, нос и рот спереди!","en":"The bag is behind, and the eyes, nose and mouth are in front!"},"Qaysi biri joy so'zi emas?":{"ru":"Какое слово не про место?","en":"Which one is not a place word?"},"Olma joy emas! Oldinda, orqada — bular tomonlar.":{"ru":"Яблоко — не место! Спереди, сзади — это стороны.","en":"Apple is not a place! In front, behind — those are sides."},"Salom, do'stim! Men Zukko. Bugun chap va o'ng tomonlarni o'rganamiz. Chap qo'l va o'ng qo'l!":{"ru":"Привет, дружок! Я Зукко. Сегодня учим левую и правую стороны. Левая рука и правая рука!","en":"Hi, friend! I'm Zukko. Today we learn left and right. Left hand and right hand!"},"Chapda — o'ngda":{"ru":"Слева — справа","en":"On the left — on the right"},"Chapda":{"ru":"Слева","en":"On the left"},"Chapda — chap tomon. Chap qo'l shu tomonda.":{"ru":"Слева — это левая сторона. Левая рука с этой стороны.","en":"On the left is the left side. The left hand is on this side."},"O'ngda":{"ru":"Справа","en":"On the right"},"O'ngda — o'ng tomon. O'ng qo'l shu tomonda.":{"ru":"Справа — это правая сторона. Правая рука с этой стороны.","en":"On the right is the right side. The right hand is on this side."},"Chap qo'l":{"ru":"Левая рука","en":"Left hand"},"Chap qo'l — chap tomonda.":{"ru":"Левая рука — с левой стороны.","en":"The left hand is on the left side."},"O'ng qo'l":{"ru":"Правая рука","en":"Right hand"},"O'ng qo'l — o'ng tomonda.":{"ru":"Правая рука — с правой стороны.","en":"The right hand is on the right side."},"Bolaning o'ng tomonida kim o'tiribdi?":{"ru":"Кто сидит справа от ребёнка?","en":"Who is sitting on the child's right side?"},"O'g'il bola o'ngda":{"ru":"Мальчик справа","en":"The boy is on the right"},"Bu o'q qaysi tomonga ko'rsatyapti?":{"ru":"В какую сторону показывает эта стрелка?","en":"Which way is this arrow pointing?"},"Chap":{"ru":"Влево","en":"Left"},"O'ng":{"ru":"Вправо","en":"Right"},"Biz qaysi qo'l bilan salom beramiz?":{"ru":"Какой рукой мы здороваемся?","en":"Which hand do we say hello with?"},"Oyoq":{"ru":"Нога","en":"Foot"},"Qaysi biri yo'nalish emas?":{"ru":"Что из этого не направление?","en":"Which one is not a direction?"},"Olma yo'nalish emas! Chap, o'ng, tepa — bular yo'nalish.":{"ru":"Яблоко — не направление! Влево, вправо, вверх — это направления.","en":"Apple is not a direction! Left, right, up — those are directions."},"Qaysi biri tomon so'zi emas?":{"ru":"Какое слово не про сторону?","en":"Which one is not a side word?"},"It tomon emas! Chap, o'ng, past — bular tomonlar.":{"ru":"Собака — не сторона! Лево, право, низ — это стороны.","en":"Dog is not a side! Left, right, bottom — those are sides."},"Salom! Men Zukko. Bugun uzoq va yaqin so'zlarini o'rganamiz. Nima yaqin, nima uzoq?":{"ru":"Привет! Я Зукко. Сегодня учим слова «далеко» и «близко». Что близко, а что далеко?","en":"Hi! I'm Zukko. Today we learn the words far and near. What is near, what is far?"},"Uzoq — yaqin":{"ru":"Далеко — близко","en":"Far — near"},"Uzoq":{"ru":"Далеко","en":"Far"},"Uzoq — juda naridagi joy. Yulduzlar uzoqda.":{"ru":"Далеко — это место очень вдали. Звёзды далеко.","en":"Far means a place very far away. The stars are far."},"Yaqin":{"ru":"Близко","en":"Near"},"Yaqin — yonimizdagi joy. Ko'zga yaqin ko'rinadi.":{"ru":"Близко — это место рядом с нами. Кажется близким глазу.","en":"Near means a place right next to us. It looks close to the eye."},"Yulduz uzoqda":{"ru":"Звезда далеко","en":"The star is far"},"Yulduzlar osmonda, juda uzoqda.":{"ru":"Звёзды в небе, очень далеко.","en":"The stars are in the sky, very far away."},"Qo'l yaqin":{"ru":"Рука близко","en":"The hand is near"},"Qo'limiz o'zimizga juda yaqin.":{"ru":"Наша рука к нам очень близко.","en":"Our hand is very near to us."},"Qaysi biri bizdan juda uzoqda?":{"ru":"Что из этого очень далеко от нас?","en":"Which one is very far from us?"},"Oy uzoqda":{"ru":"Луна далеко","en":"The moon is far"},"Oyoq kiyim yaqin":{"ru":"Обувь близко","en":"The shoes are near"},"Qaysi biri bizga eng yaqin?":{"ru":"Что из этого к нам ближе всего?","en":"Which one is nearest to us?"},"Quyosh uzoqda":{"ru":"Солнце далеко","en":"The sun is far"},"Burun yaqin":{"ru":"Нос близко","en":"The nose is near"},"Yulduz va uy — qaysi biri uzoqroq?":{"ru":"Звезда и дом — что из них дальше?","en":"Star and house — which one is farther?"},"Uy yaqin":{"ru":"Дом близко","en":"The house is near"},"Yulduz uzoq":{"ru":"Звезда далеко","en":"The star is far"},"Daraxt yaqin":{"ru":"Дерево близко","en":"The tree is near"},"Qo'limizdagi kitob bizga qanday?":{"ru":"Книга в наших руках — какая для нас?","en":"The book in our hands — how is it to us?"},"Juda uzoq":{"ru":"Очень далеко","en":"Very far"},"Quyosh bizga juda yaqin.":{"ru":"Солнце к нам очень близко.","en":"The sun is very near to us."},"Yolg'on! Quyosh juda uzoqda.":{"ru":"Неправда! Солнце очень далеко.","en":"False! The sun is very far away."},"Bizning qo'limiz o'zimizga yaqin.":{"ru":"Наша рука к нам близко.","en":"Our hand is near to us."},"Rost! Qo'l juda yaqin.":{"ru":"Правда! Рука очень близко.","en":"True! The hand is very near."},"Yulduzlar osmonda uzoqda.":{"ru":"Звёзды в небе далеко.","en":"The stars are far away in the sky."},"Rost! Yulduzlar juda uzoqda.":{"ru":"Правда! Звёзды очень далеко.","en":"True! The stars are very far away."},"Oyog'imizdagi poyabzal uzoqda.":{"ru":"Обувь на наших ногах далеко.","en":"The shoes on our feet are far."},"Yolg'on! Poyabzal bizga yaqin.":{"ru":"Неправда! Обувь к нам близко.","en":"False! The shoes are near to us."},"Salom, do'stim! Men Zukko. Bugun yo'nalishlarni o'rganamiz. O'qlar yo'l ko'rsatadi!":{"ru":"Привет, дружок! Я Зукко. Сегодня учим направления. Стрелки показывают путь!","en":"Hi, friend! I'm Zukko. Today we learn directions. Arrows show the way!"},"Yo'l va yo'nalish":{"ru":"Путь и направление","en":"Path and direction"},"Yuqoriga":{"ru":"Вверх","en":"Up"},"Yuqoriga — oldinga, tepa tomon yuramiz.":{"ru":"Вверх — идём вперёд, в сторону верха.","en":"Up — we go forward, toward the top."},"Pastga":{"ru":"Вниз","en":"Down"},"Pastga — quyi tomon yuramiz.":{"ru":"Вниз — идём в сторону низа.","en":"Down — we go toward the bottom."},"Chapga":{"ru":"Налево","en":"Left"},"Chapga — chap tomonga buriladi.":{"ru":"Налево — поворачиваем в левую сторону.","en":"Left — we turn to the left side."},"O'ngga":{"ru":"Направо","en":"Right"},"O'ngga — o'ng tomonga buriladi.":{"ru":"Направо — поворачиваем в правую сторону.","en":"Right — we turn to the right side."},"Uydan maktabga yo'lni tartib bilan bos!":{"ru":"Нажимай по порядку путь от дома до школы!","en":"Tap the path from home to school in order!"},"Uy":{"ru":"Дом","en":"House"},"O'ngga bur":{"ru":"Поверни направо","en":"Turn right"},"Yuqoriga yur":{"ru":"Иди вверх","en":"Go up"},"Mashina qaysi tomonga burildi?":{"ru":"В какую сторону повернула машина?","en":"Which way did the car turn?"},"Bu o'q qayerga yur deydi?":{"ru":"Куда велит идти эта стрелка?","en":"Where does this arrow tell us to go?"},"Bola qaysi tomonga yurdi?":{"ru":"В какую сторону пошёл ребёнок?","en":"Which way did the child go?"},"Yo'lni to'g'ri kesib o'tish uchun avval qayerga qaraymiz?":{"ru":"Чтобы правильно перейти дорогу, куда сначала смотрим?","en":"To cross the road correctly, where do we look first?"},"Chapga qaraymiz":{"ru":"Смотрим налево","en":"We look left"},"Tepaga":{"ru":"Наверх","en":"Up"},"Salom! Men Zukko. Bugun uzun va qisqa so'zlarini o'rganamiz. Qaysi yo'l uzun, qaysi biri qisqa?":{"ru":"Привет! Я Зукко. Сегодня учим слова «длинный» и «короткий». Какая дорога длинная, а какая короткая?","en":"Hi! I'm Zukko. Today we learn the words long and short. Which path is long, which is short?"},"Uzun — qisqa":{"ru":"Длинный — короткий","en":"Long — short"},"Uzun":{"ru":"Длинный","en":"Long"},"Uzun — juda katta, cho'zilgan narsa.":{"ru":"Длинный — очень большой, вытянутый предмет.","en":"Long means a very big, stretched-out thing."},"Qisqa":{"ru":"Короткий","en":"Short"},"Qisqa — kichik, kaltagina narsa.":{"ru":"Короткий — маленький, коротенький предмет.","en":"Short means a small, little thing."},"Ilon uzun":{"ru":"Змея длинная","en":"The snake is long"},"Ilon uzun bo'ladi.":{"ru":"Змея бывает длинной.","en":"A snake is long."},"Qurt qisqa":{"ru":"Червячок короткий","en":"The worm is short"},"Qurtcha qisqa bo'ladi.":{"ru":"Червячок бывает коротким.","en":"A little worm is short."},"Qisqadan boshlab, uzunga qarab bosing!":{"ru":"Нажимай от короткого к длинному!","en":"Tap from short to long!"},"O'rtacha":{"ru":"Средний","en":"Medium"},"Ilon va qurt — qaysi biri uzunroq?":{"ru":"Змея и червячок — кто из них длиннее?","en":"Snake and worm — which one is longer?"},"Kim tezroq yetib boradi?":{"ru":"Кто доберётся быстрее?","en":"Who gets there faster?"},"Piyoda sekin":{"ru":"Пешеход медленный","en":"The walker is slow"},"Mashina tez":{"ru":"Машина быстрая","en":"The car is fast"},"Toshbaqa sekin":{"ru":"Черепаха медленная","en":"The turtle is slow"},"Qaysi biri qisqa?":{"ru":"Что из этого короткое?","en":"Which one is short?"},"Qisqa yo'ldan yursak nima bo'ladi?":{"ru":"Что будет, если пойти короткой дорогой?","en":"What happens if we take the short path?"},"Tez yetamiz":{"ru":"Придём быстро","en":"We get there fast"},"Sekin qolamiz":{"ru":"Опоздаем","en":"We fall behind"},"Uxlaymiz":{"ru":"Будем спать","en":"We sleep"},"Salom, do'stim! Men Zukko. Bugun xavfsizlik qoidalarini o'rganamiz. Qayerda xavfsiz, qayerda xavfli?":{"ru":"Привет, дружок! Я Зукко. Сегодня учим правила безопасности. Где безопасно, а где опасно?","en":"Hi, friend! I'm Zukko. Today we learn safety rules. Where is it safe, where is it dangerous?"},"Xavfsiz hudud":{"ru":"Безопасное место","en":"Safe zone"},"Svetofor":{"ru":"Светофор","en":"Traffic light"},"Svetofor yo'lni xavfsiz kesishga yordam beradi.":{"ru":"Светофор помогает безопасно перейти дорогу.","en":"The traffic light helps us cross the road safely."},"Xavfsizlik jileti":{"ru":"Светоотражающий жилет","en":"Safety vest"},"Jilet bizni ko'rinadigan qiladi, xavfsiz saqlaydi.":{"ru":"Жилет делает нас заметными и бережёт нас.","en":"The vest makes us visible and keeps us safe."},"Piyodalar yo'li":{"ru":"Пешеходный переход","en":"Crosswalk"},"Bu belgi bolalar o'tadigan xavfsiz joy.":{"ru":"Этот знак — безопасное место, где переходят дети.","en":"This sign marks a safe place where children cross."},"To'xta":{"ru":"Стой","en":"Stop"},"Xavf bo'lsa to'xtaymiz va qaraymiz.":{"ru":"Если опасно, останавливаемся и смотрим.","en":"If it's dangerous, we stop and look."},"Yashil chiroqda yo'ldan o'tamiz.":{"ru":"На зелёный свет переходим дорогу.","en":"We cross the road on the green light."},"Rost! Yashil chiroqda o'tish xavfsiz.":{"ru":"Правда! Переходить на зелёный свет безопасно.","en":"True! Crossing on the green light is safe."},"Qizil chiroqda yo'ldan yuguramiz.":{"ru":"На красный свет бежим через дорогу.","en":"We run across the road on the red light."},"Yolg'on! Qizil chiroqda to'xtaymiz.":{"ru":"Неправда! На красный свет мы останавливаемся.","en":"False! On the red light we stop."},"Yo'lni piyodalar o'tish joyidan kechamiz.":{"ru":"Дорогу переходим по пешеходному переходу.","en":"We cross the road at the crosswalk."},"Rost! Piyodalar yo'li xavfsiz joy.":{"ru":"Правда! Пешеходный переход — безопасное место.","en":"True! The crosswalk is a safe place."},"Olov bilan o'ynash xavfsiz.":{"ru":"Играть с огнём безопасно.","en":"Playing with fire is safe."},"Yolg'on! Olov juda xavfli, o'ynamaymiz.":{"ru":"Неправда! Огонь очень опасен, мы не играем с ним.","en":"False! Fire is very dangerous, we don't play with it."},"Yo'lga chiqishdan oldin ikki tomonga qaraymiz.":{"ru":"Перед выходом на дорогу смотрим в обе стороны.","en":"Before stepping onto the road, we look both ways."},"Rost! Avval qaraymiz, keyin o'tamiz.":{"ru":"Правда! Сначала смотрим, потом переходим.","en":"True! First we look, then we cross."},"Qaysi holat xavfli?":{"ru":"Какая ситуация опасна?","en":"Which situation is dangerous?"},"Olov xavfli! Svetofor, jilet, piyoda yo'li — bular xavfsiz.":{"ru":"Огонь опасен! Светофор, жилет, пешеходный переход — это безопасно.","en":"Fire is dangerous! Traffic light, vest, crosswalk — these are safe."},"Qaysi biri xavfsizlik yordamchisi emas?":{"ru":"Что из этого не помощник по безопасности?","en":"Which one is not a safety helper?"},"Konfet xavfsizlik yordamchisi emas! Svetofor, jilet, politsiyachi yordam beradi.":{"ru":"Конфета — не помощник по безопасности! Светофор, жилет, полицейский помогают.","en":"Candy is not a safety helper! The traffic light, vest and police officer help."},"Salom! Men Zukko. Bugun labirintdan yo'l topamiz. O'qlarga qarab harakat qilamiz!":{"ru":"Привет! Я Зукко. Сегодня ищем путь в лабиринте. Двигаемся по стрелкам!","en":"Hi! I'm Zukko. Today we find the way through a maze. We move by the arrows!"},"Labirint":{"ru":"Лабиринт","en":"Maze"},"Labirint — chalkash yo'llar. To'g'ri yo'lni topamiz.":{"ru":"Лабиринт — это запутанные дорожки. Найдём верный путь.","en":"A maze is a tangle of paths. We find the right way."},"Labirintda yuqoriga qadam qo'yamiz.":{"ru":"В лабиринте шагаем вверх.","en":"In the maze we step up."},"O'ngga yur":{"ru":"Иди направо","en":"Go right"},"Labirintda o'ngga buriladi.":{"ru":"В лабиринте поворачиваем направо.","en":"In the maze we turn right."},"Maqsad":{"ru":"Цель","en":"Goal"},"Maqsad — yetib boradigan oxirgi joy.":{"ru":"Цель — последнее место, куда нужно дойти.","en":"The goal is the final place we reach."},"Labirintdan uyga yetish uchun qadamlarni tartibla!":{"ru":"Расставь шаги по порядку, чтобы дойти из лабиринта до дома!","en":"Put the steps in order to get home through the maze!"},"Sichqon boshladi":{"ru":"Мышка начала","en":"The mouse started"},"Yana yuqoriga":{"ru":"Снова вверх","en":"Up again"},"Pishloqqa yetdi":{"ru":"Дошла до сыра","en":"Reached the cheese"},"Labirintda to'g'ri yo'lni topsak qayerga yetamiz?":{"ru":"Куда мы придём, если найдём верный путь в лабиринте?","en":"Where do we get if we find the right way in the maze?"},"Maqsadga":{"ru":"К цели","en":"To the goal"},"Yomg'irga":{"ru":"Под дождь","en":"Into the rain"},"Uyquga":{"ru":"В сон","en":"To sleep"},"Uyga yetish uchun necha marta o'ngga burilish kerak?":{"ru":"Сколько раз нужно повернуть направо, чтобы дойти до дома?","en":"How many times do we turn right to reach home?"},"Bir marta":{"ru":"Один раз","en":"Once"},"Ikki marta":{"ru":"Два раза","en":"Twice"},"Besh marta":{"ru":"Пять раз","en":"Five times"},"Labirintda bu o'q qayerga yur deydi?":{"ru":"Куда велит идти эта стрелка в лабиринте?","en":"Where does this arrow tell us to go in the maze?"},"Sichqon labirintdan nima izlaydi?":{"ru":"Что ищет мышка в лабиринте?","en":"What is the mouse looking for in the maze?"},"Pishloq":{"ru":"Сыр","en":"Cheese"},"To'p":{"ru":"Мяч","en":"Ball"},"Salom, do'stim! Men Zukko. Bugun maktabdan uyga xavfsiz qaytishni o'rganamiz. Eng xavfsiz yo'lni tanlaymiz!":{"ru":"Привет, дружок! Я Зукко. Сегодня учимся безопасно возвращаться из школы домой. Выбираем самый безопасный путь!","en":"Hi, friend! I'm Zukko. Today we learn to get home from school safely. We choose the safest path!"},"Maktabdan uyga qaytish yo'li":{"ru":"Путь из школы домой","en":"The way home from school"},"Maktab — o'qiydigan joyimiz. Uydan yo'l shu yerdan boshlanadi.":{"ru":"Школа — место, где мы учимся. Отсюда начинается путь домой.","en":"School is where we study. The way home starts here."},"Xavfsiz o'tish":{"ru":"Безопасный переход","en":"Safe crossing"},"Yashil chiroqni kutamiz, keyin o'tamiz.":{"ru":"Ждём зелёный свет, потом переходим.","en":"We wait for the green light, then cross."},"Uy — xavfsiz yetib boradigan joyimiz.":{"ru":"Дом — место, куда мы приходим в безопасности.","en":"Home is the safe place we reach."},"Maktabdan uyga yo'lni tartib bilan bos!":{"ru":"Нажимай по порядку путь из школы домой!","en":"Tap the path from school to home in order!"},"Piyoda yo'lida":{"ru":"На пешеходном переходе","en":"At the crosswalk"},"Svetoforda":{"ru":"У светофора","en":"At the traffic light"},"Rost! Bu eng xavfsiz joy.":{"ru":"Правда! Это самое безопасное место.","en":"True! This is the safest place."},"Rost! Yashil chiroq o'tishga ruxsat beradi.":{"ru":"Правда! Зелёный свет разрешает переходить.","en":"True! The green light allows us to cross."},"Yo'lda mashinalar orasidan yuguramiz.":{"ru":"Бежим между машинами по дороге.","en":"We run between cars on the road."},"Yolg'on! Bu juda xavfli. Piyoda yo'lidan yuramiz.":{"ru":"Неправда! Это очень опасно. Ходим по пешеходному переходу.","en":"False! That's very dangerous. We use the crosswalk."},"Kichkina bolalar yo'lda kattalar bilan yuradi.":{"ru":"Маленькие дети ходят по дороге со взрослыми.","en":"Little children walk on the road with grown-ups."},"Rost! Kattalar bilan yurish xavfsiz.":{"ru":"Правда! Ходить со взрослыми безопасно.","en":"True! Walking with grown-ups is safe."},"Uyga qaysi yo'l xavfsizroq?":{"ru":"Какая дорога домой безопаснее?","en":"Which way home is safer?"},"Piyoda yo'li":{"ru":"Пешеходная дорожка","en":"Footpath"},"Mashina yo'li":{"ru":"Проезжая часть","en":"Car road"},"Suv bo'yi":{"ru":"Берег","en":"Waterside"},"Yo'ldan qaysi chiroqda o'tamiz?":{"ru":"На какой свет мы переходим дорогу?","en":"On which light do we cross the road?"},"Ikki yo'ldan qaysi biri qisqaroq bo'lsa yaxshi?":{"ru":"Из двух дорог какую лучше выбрать — покороче?","en":"Of two paths, which is better to be shorter?"},"Qisqa yo'l":{"ru":"Короткая дорога","en":"Short path"},"Uzun yo'l":{"ru":"Длинная дорога","en":"Long path"},"Chalkash yo'l":{"ru":"Запутанная дорога","en":"Tangled path"},"Salom, do'stim! Men Zukko. Bugun narsalar qanday qismlardan tuzilishini o'rganamiz. Keling, boshladik!":{"ru":"Привет, дружок! Я Зукко. Сегодня узнаем, из каких частей состоят предметы. Давай начнём!","en":"Hi, friend! I'm Zukko. Today we'll learn what parts things are made of. Let's begin!"},"Narsalarni qismlarga ajratish":{"ru":"Разбираем предметы на части","en":"Breaking things into parts"},"Uy tom, devor, eshik va derazadan iborat.":{"ru":"Дом состоит из крыши, стен, двери и окна.","en":"A house has a roof, walls, a door and a window."},"Daraxtda tana, shox va barglar bor.":{"ru":"У дерева есть ствол, ветки и листья.","en":"A tree has a trunk, branches and leaves."},"Mashinada g'ildirak, eshik va oyna bor.":{"ru":"У машины есть колёса, двери и окна.","en":"A car has wheels, doors and windows."},"Quyosh":{"ru":"Солнце","en":"Sun"},"Quyoshda yumaloq shar va nurlar bor.":{"ru":"У солнца есть круглый шар и лучи.","en":"The sun has a round ball and rays."},"Gulda gulbarg, poya va barglar bor.":{"ru":"У цветка есть лепестки, стебель и листья.","en":"A flower has petals, a stem and leaves."},"Avval yuqoridan birini bos, keyin uning qismini bos!":{"ru":"Сначала нажми на один сверху, потом на его часть!","en":"First tap one at the top, then tap its part!"},"Barg":{"ru":"Лист","en":"Leaf"},"G'ildirak":{"ru":"Колесо","en":"Wheel"},"Gulbarg":{"ru":"Лепесток","en":"Petal"},"Qaysi qism uyga tegishli emas?":{"ru":"Какая часть не относится к дому?","en":"Which part does not belong to the house?"},"Qurbaqa uyning qismi emas!":{"ru":"Лягушка — не часть дома!","en":"A frog is not a part of the house!"},"Qaysi qism mashinaga tegishli emas?":{"ru":"Какая часть не относится к машине?","en":"Which part does not belong to the car?"},"Banan mashinaning qismi emas!":{"ru":"Банан — не часть машины!","en":"A banana is not a part of the car!"},"Qaysi qism daraxtga tegishli emas?":{"ru":"Какая часть не относится к дереву?","en":"Which part does not belong to the tree?"},"Baliq daraxtning qismi emas!":{"ru":"Рыба — не часть дерева!","en":"A fish is not a part of the tree!"},"Salom! Men Zukko. Qismlardan yaxlit narsa yasaymiz. Xuddi konstruktor kabi, keling yig'amiz!":{"ru":"Привет! Я Зукко. Из частей сделаем целый предмет. Как из конструктора, давай соберём!","en":"Hi! I'm Zukko. We'll make a whole thing from parts. Just like a construction set, let's build it!"},"Turli qismlardan yaxlit narsani yig'ish":{"ru":"Собираем целое из разных частей","en":"Building a whole from different parts"},"G'ishtlar":{"ru":"Кирпичи","en":"Bricks"},"Ko'p g'ishtdan chiroyli qasr yasash mumkin.":{"ru":"Из множества кирпичей можно построить красивый замок.","en":"You can build a beautiful castle from many bricks."},"Qasr":{"ru":"Замок","en":"Castle"},"Qasr g'ishtlardan yig'iladi.":{"ru":"Замок собирают из кирпичей.","en":"A castle is built from bricks."},"Puzzle":{"ru":"Пазл","en":"Puzzle"},"Kichik qismlardan katta rasm yig'iladi.":{"ru":"Из маленьких частей собирается большая картинка.","en":"A big picture is made from small pieces."},"Tort":{"ru":"Торт","en":"Cake"},"Un, tuxum va shakardan tort tayyorlanadi.":{"ru":"Торт готовят из муки, яиц и сахара.","en":"A cake is made from flour, eggs and sugar."},"G'ishtlardan nima yasash mumkin?":{"ru":"Что можно сделать из кирпичей?","en":"What can you make from bricks?"},"Puzzle qismlaridan nima yig'iladi?":{"ru":"Что собирается из кусочков пазла?","en":"What is made from puzzle pieces?"},"Rasm":{"ru":"Картинка","en":"Picture"},"Banan":{"ru":"Банан","en":"Banana"},"Un va tuxumdan nima tayyorlanadi?":{"ru":"Что готовят из муки и яиц?","en":"What is made from flour and eggs?"},"Qor odam yasashda qaysi qism ortiqcha?":{"ru":"Какая часть лишняя при лепке снеговика?","en":"Which part is extra when making a snowman?"},"Pitsa qor odamga kerak emas!":{"ru":"Пицца снеговику не нужна!","en":"A pizza is not needed for a snowman!"},"Uy qurishda qaysi qism ortiqcha?":{"ru":"Какая часть лишняя при постройке дома?","en":"Which part is extra when building a house?"},"Sharcha uy qismi emas!":{"ru":"Шарик — не часть дома!","en":"A balloon is not a part of the house!"},"Salom, aziz do'stim! Men Zukko. Bugun narsalarni taqqoslaymiz: rangi, shakli va o'lchamini solishtiramiz!":{"ru":"Привет, дорогой дружок! Я Зукко. Сегодня сравним предметы: их цвет, форму и размер!","en":"Hi, dear friend! I'm Zukko. Today we'll compare things: their colour, shape and size!"},"Taqqoslash":{"ru":"Сравнение","en":"Comparison"},"Narsalar rangi bilan farq qiladi: qizil, ko'k, sariq.":{"ru":"Предметы отличаются цветом: красный, синий, жёлтый.","en":"Things differ by colour: red, blue, yellow."},"Narsalar shakli har xil: kvadrat, dumaloq, uchburchak.":{"ru":"У предметов разная форма: квадрат, круг, треугольник.","en":"Things have different shapes: square, round, triangle."},"Narsa katta yoki kichik bo'lishi mumkin.":{"ru":"Предмет может быть большим или маленьким.","en":"A thing can be big or small."},"Taqqoslab, o'xshash va farqli tomonlarni topamiz.":{"ru":"Сравнивая, находим сходства и различия.","en":"By comparing, we find what's alike and what's different."},"Qaysi biri kattaroq?":{"ru":"Кто из них больше?","en":"Which one is bigger?"},"Sichqon":{"ru":"Мышка","en":"Mouse"},"Qaysi biri qizil rangda?":{"ru":"Который из них красного цвета?","en":"Which one is red?"},"Qizil yurak":{"ru":"Красное сердце","en":"Red heart"},"Ko'k yurak":{"ru":"Синее сердце","en":"Blue heart"},"Yashil yurak":{"ru":"Зелёное сердце","en":"Green heart"},"Qaysi biri dumaloq shaklda?":{"ru":"Который из них круглой формы?","en":"Which one is round?"},"Ruchka":{"ru":"Ручка","en":"Pen"},"Qaysi biri balandroq?":{"ru":"Который из них выше?","en":"Which one is taller?"},"Qo'ziqorin":{"ru":"Гриб","en":"Mushroom"},"Qaysi biri boshqacha (farqli)?":{"ru":"Который из них другой (отличается)?","en":"Which one is different?"},"Ko'k doira boshqa rangda!":{"ru":"Синий круг другого цвета!","en":"The blue circle is a different colour!"},"Banan boshqa meva!":{"ru":"Банан — другой фрукт!","en":"The banana is a different fruit!"},"Salom! Men Zukko. Bugun qarama-qarshi so'zlarni o'rganamiz: katta va kichik, issiq va sovuq!":{"ru":"Привет! Я Зукко. Сегодня узнаем слова-противоположности: большой и маленький, горячий и холодный!","en":"Hi! I'm Zukko. Today we'll learn opposite words: big and small, hot and cold!"},"Qarama-qarshi belgilar":{"ru":"Противоположные признаки","en":"Opposite qualities"},"Katta":{"ru":"Большой","en":"Big"},"Katta narsa keng va yirik bo'ladi.":{"ru":"Большой предмет широкий и крупный.","en":"A big thing is wide and large."},"Kichik":{"ru":"Маленький","en":"Small"},"Kichik narsa mayda bo'ladi. U kattaning aksi.":{"ru":"Маленький предмет крошечный. Он противоположность большого.","en":"A small thing is tiny. It's the opposite of big."},"Olov issiq. Uning aksi — sovuq.":{"ru":"Огонь горячий. Его противоположность — холодный.","en":"Fire is hot. Its opposite is cold."},"Qor sovuq. U issiqning aksi.":{"ru":"Снег холодный. Он противоположность горячего.","en":"Snow is cold. It's the opposite of hot."},"Avval yuqoridan birini bos, keyin uning aksini bos!":{"ru":"Сначала нажми на один сверху, потом на его противоположность!","en":"First tap one at the top, then tap its opposite!"},"Xursand":{"ru":"Весёлый","en":"Happy"},"Xafa":{"ru":"Грустный","en":"Sad"},"Kattaning aksi nima?":{"ru":"Что противоположно большому?","en":"What is the opposite of big?"},"Kichik sichqon":{"ru":"Маленькая мышка","en":"Small mouse"},"Katta fil":{"ru":"Большой слон","en":"Big elephant"},"Baland daraxt":{"ru":"Высокое дерево","en":"Tall tree"},"Issiqning aksi nima?":{"ru":"Что противоположно горячему?","en":"What is the opposite of hot?"},"Sovuq qor":{"ru":"Холодный снег","en":"Cold snow"},"Issiq olov":{"ru":"Горячий огонь","en":"Hot fire"},"Issiq quyosh":{"ru":"Горячее солнце","en":"Hot sun"},"Kunduzning aksi nima?":{"ru":"Что противоположно дню?","en":"What is the opposite of day?"},"Yulduz":{"ru":"Звезда","en":"Star"},"Salom, do'stim! Men Zukko. Bugun \"ha\" va \"yo'q\" so'zlarini o'rganamiz. Tasdiq va inkor!":{"ru":"Привет, дружок! Я Зукко. Сегодня узнаем слова «да» и «нет». Утверждение и отрицание!","en":"Hi, friend! I'm Zukko. Today we'll learn the words \"yes\" and \"no\". Yes and no!"},"Tasdiq — inkor":{"ru":"Да — нет","en":"Yes — no"},"Tasdiq":{"ru":"Да","en":"Yes"},"Tasdiq — bu \"ha\", to'g'ri degani.":{"ru":"«Да» значит «верно», это правильно.","en":"\"Yes\" means \"correct\", it's right."},"Inkor":{"ru":"Нет","en":"No"},"Inkor — bu \"yo'q\", noto'g'ri degani.":{"ru":"«Нет» значит «неверно», это неправильно.","en":"\"No\" means \"incorrect\", it's wrong."},"Ha":{"ru":"Да","en":"Yes"},"Ha desak, biz roziligimizni bildiramiz.":{"ru":"Когда мы говорим «да», мы соглашаемся.","en":"When we say \"yes\", we agree."},"Yo'q":{"ru":"Нет","en":"No"},"Yo'q desak, biz rad etamiz.":{"ru":"Когда мы говорим «нет», мы отказываемся.","en":"When we say \"no\", we refuse."},"Olma — meva.":{"ru":"Яблоко — это фрукт.","en":"An apple is a fruit."},"To'g'ri, olma mevadir!":{"ru":"Верно, яблоко — это фрукт!","en":"Correct, an apple is a fruit!"},"Qush uchadi.":{"ru":"Птица летает.","en":"A bird flies."},"Ha, qushlar ucha oladi!":{"ru":"Да, птицы умеют летать!","en":"Yes, birds can fly!"},"Baliq osmonda yashaydi.":{"ru":"Рыба живёт в небе.","en":"A fish lives in the sky."},"Yo'q, baliq suvda yashaydi!":{"ru":"Нет, рыба живёт в воде!","en":"No, a fish lives in the water!"},"Oy kechasi chiqadi.":{"ru":"Луна выходит ночью.","en":"The moon comes out at night."},"To'g'ri, oy tunda ko'rinadi!":{"ru":"Верно, луну видно ночью!","en":"Correct, the moon is seen at night!"},"Qaysi gap to'g'ri (tasdiq)?":{"ru":"Какое предложение верное (да)?","en":"Which sentence is true (yes)?"},"It vovullaydi":{"ru":"Собака лает","en":"A dog barks"},"Mushuk uchadi":{"ru":"Кошка летает","en":"A cat flies"},"Baliq yuguradi":{"ru":"Рыба бегает","en":"A fish runs"},"Quyosh yorug'lik beradi":{"ru":"Солнце даёт свет","en":"The sun gives light"},"Muz issiq":{"ru":"Лёд горячий","en":"Ice is hot"},"Tosh yumshoq":{"ru":"Камень мягкий","en":"A stone is soft"},"Asalari asal yig'adi":{"ru":"Пчела собирает мёд","en":"A bee collects honey"},"Fil mitti":{"ru":"Слон крошечный","en":"An elephant is tiny"},"Limon shirin":{"ru":"Лимон сладкий","en":"A lemon is sweet"},"Salom! Men Zukko. Bugun rost va yolg'onni ajratamiz. Qaysi gap to'g'ri, qaysi biri noto'g'ri?":{"ru":"Привет! Я Зукко. Сегодня отличим правду от неправды. Какое предложение верное, а какое нет?","en":"Hi! I'm Zukko. Today we'll tell true from false. Which sentence is right, and which is wrong?"},"Rost va yolg'on":{"ru":"Правда и неправда","en":"True and false"},"Rost":{"ru":"Правда","en":"True"},"Rost — bu haqiqat, to'g'ri gap.":{"ru":"Правда — это то, что есть на самом деле, верное предложение.","en":"True is what's real, a correct statement."},"Yolg'on":{"ru":"Неправда","en":"False"},"Yolg'on — bu noto'g'ri, haqiqat emas.":{"ru":"Неправда — это неверно, не по-настоящему.","en":"False is what's wrong, not real."},"O'ylash":{"ru":"Размышление","en":"Thinking"},"Gap rostmi yoki yolg'onmi, o'ylab ko'ramiz.":{"ru":"Подумаем, правда предложение или неправда.","en":"Let's think whether the sentence is true or false."},"Quyosh kunduzi porlaydi.":{"ru":"Солнце светит днём.","en":"The sun shines in the daytime."},"Rost, quyosh kunduzi chiqadi!":{"ru":"Правда, солнце выходит днём!","en":"True, the sun comes out in the daytime!"},"Fil juda kichkina hayvon.":{"ru":"Слон — очень маленькое животное.","en":"An elephant is a very small animal."},"Yolg'on, fil juda katta!":{"ru":"Неправда, слон очень большой!","en":"False, an elephant is very big!"},"Qishda qor yog'adi.":{"ru":"Зимой идёт снег.","en":"In winter it snows."},"Rost, qishda sovuq va qor bo'ladi!":{"ru":"Правда, зимой холодно и идёт снег!","en":"True, in winter it's cold and snowy!"},"Baliq suvda suzadi.":{"ru":"Рыба плавает в воде.","en":"A fish swims in the water."},"Rost, baliqlar suvda yashaydi!":{"ru":"Правда, рыбы живут в воде!","en":"True, fish live in the water!"},"Limon juda shirin.":{"ru":"Лимон очень сладкий.","en":"A lemon is very sweet."},"Yolg'on, limon nordon!":{"ru":"Неправда, лимон кислый!","en":"False, a lemon is sour!"},"Qaysi gap rost?":{"ru":"Какое предложение правдивое?","en":"Which sentence is true?"},"Qush qanoti bor":{"ru":"У птицы есть крылья","en":"A bird has wings"},"Baliq yuradi":{"ru":"Рыба ходит","en":"A fish walks"},"Daraxt uchadi":{"ru":"Дерево летает","en":"A tree flies"},"Asal shirin":{"ru":"Мёд сладкий","en":"Honey is sweet"},"Oy kunduzi porlaydi":{"ru":"Луна светит днём","en":"The moon shines in the daytime"},"Toshbaqa sekin yuradi":{"ru":"Черепаха ходит медленно","en":"A tortoise walks slowly"},"Quyon sekin":{"ru":"Заяц медленный","en":"A rabbit is slow"},"Yaguar sekin":{"ru":"Ягуар медленный","en":"A jaguar is slow"},"Salom, aziz do'stim! Men Zukko. Bugun har bir ishga eng kerakli narsani tanlaymiz. Keling, boshladik!":{"ru":"Привет, дорогой дружок! Я Зукко. Сегодня для каждого дела выберем самое нужное. Давай начнём!","en":"Hi, dear friend! I'm Zukko. Today we'll pick the most needed thing for each task. Let's begin!"},"Eng keraklisi":{"ru":"Самое нужное","en":"The most needed"},"Matematika":{"ru":"Математика","en":"Maths"},"Matematika darsiga chizg'ich va sonlar kerak.":{"ru":"Для урока математики нужны линейка и числа.","en":"For a maths lesson you need a ruler and numbers."},"Musiqa darsiga cholg'u asboblari kerak.":{"ru":"Для урока музыки нужны музыкальные инструменты.","en":"For a music lesson you need musical instruments."},"Yozda yengil, salqin kiyimlar kerak.":{"ru":"Летом нужна лёгкая, прохладная одежда.","en":"In summer you need light, cool clothes."},"Qishda issiq kiyimlar va qo'lqop kerak.":{"ru":"Зимой нужна тёплая одежда и варежки.","en":"In winter you need warm clothes and mittens."},"Avval yuqoridan birini bos, keyin unga kerakli narsani bos!":{"ru":"Сначала нажми на один сверху, потом на нужную ему вещь!","en":"First tap one at the top, then tap the thing it needs!"},"Chizg'ich":{"ru":"Линейка","en":"Ruler"},"Pianino":{"ru":"Пианино","en":"Piano"},"Matematika darsiga nima kerak?":{"ru":"Что нужно для урока математики?","en":"What do you need for a maths lesson?"},"Pitsa":{"ru":"Пицца","en":"Pizza"},"Sharcha":{"ru":"Шарик","en":"Balloon"},"Rasm chizishga nima kerak?":{"ru":"Что нужно, чтобы рисовать?","en":"What do you need to draw?"},"Mo'yqalam":{"ru":"Кисточка","en":"Paintbrush"},"Yomg'irda nima kerak?":{"ru":"Что нужно в дождь?","en":"What do you need in the rain?"},"Soyabon":{"ru":"Зонт","en":"Umbrella"},"Ko'zoynak":{"ru":"Очки","en":"Glasses"},"Muzqaymoq":{"ru":"Мороженое","en":"Ice cream"},"Maktabga qaysi narsa kerak emas?":{"ru":"Какая вещь не нужна в школе?","en":"Which thing is not needed at school?"},"Tova maktabga kerak emas!":{"ru":"Сковорода в школе не нужна!","en":"A frying pan is not needed at school!"},"Qishda qaysi narsa kerak emas?":{"ru":"Какая вещь не нужна зимой?","en":"Which thing is not needed in winter?"},"Shippak qishda kerak emas!":{"ru":"Тапочки зимой не нужны!","en":"Slippers are not needed in winter!"},"Salom, qahramonim! Men Zukko. Bu bizning oxirgi darsimiz! Ishni to'g'ri va oxirigacha qilishni o'rganamiz. Yashasin!":{"ru":"Привет, мой герой! Я Зукко. Это наш последний урок! Научимся делать дело правильно и до конца. Ура!","en":"Hi, my hero! I'm Zukko. This is our last lesson! We'll learn to do a job right and all the way to the end. Hooray!"},"Samarali natija":{"ru":"Хороший результат","en":"A good result"},"To'g'ri":{"ru":"Правильно","en":"Correctly"},"Ishni to'g'ri bajarsak, natija chiroyli bo'ladi.":{"ru":"Если сделать дело правильно, результат будет красивым.","en":"If we do the job right, the result will be nice."},"O'z vaqtida":{"ru":"Вовремя","en":"On time"},"Ishni o'z vaqtida qilsak, kechikmaymiz.":{"ru":"Если делать дело вовремя, мы не опоздаем.","en":"If we do the job on time, we won't be late."},"Oxirigacha":{"ru":"До конца","en":"To the end"},"Boshlagan ishni oxirigacha yetkazamiz.":{"ru":"Начатое дело доводим до конца.","en":"We finish what we started all the way."},"Foydali":{"ru":"Полезно","en":"Useful"},"Ish foydali bo'lsa, hammaga yordam beradi.":{"ru":"Если дело полезное, оно всем помогает.","en":"If a job is useful, it helps everyone."},"Boshlagan ishni oxirigacha qilish yaxshi.":{"ru":"Хорошо доводить начатое дело до конца.","en":"It's good to finish what you started."},"Rost! Ishni tugatish kerak.":{"ru":"Правда! Дело нужно завершать.","en":"True! You should finish the job."},"Darsga kechikish yaxshi.":{"ru":"Опаздывать на урок — хорошо.","en":"Being late for a lesson is good."},"Yolg'on! O'z vaqtida kelish kerak.":{"ru":"Неправда! Нужно приходить вовремя.","en":"False! You should come on time."},"Ishni to'g'ri bajarish muhim.":{"ru":"Важно выполнять дело правильно.","en":"It's important to do the job right."},"Rost! To'g'ri ishlash muhim.":{"ru":"Правда! Важно работать правильно.","en":"True! It's important to work correctly."},"O'z ishingni tozalab qo'yish yaxshi.":{"ru":"Хорошо убирать за собой.","en":"It's good to clean up after yourself."},"Rost! Tartib yaxshi odat.":{"ru":"Правда! Порядок — хорошая привычка.","en":"True! Tidiness is a good habit."},"Uyning qismi qaysi?":{"ru":"Какая часть у дома?","en":"Which is a part of the house?"},"Baliq":{"ru":"Рыба","en":"Fish"},"Matematikaga nima kerak?":{"ru":"Что нужно для математики?","en":"What do you need for maths?"},"Qush uchadi":{"ru":"Птица летает","en":"A bird flies"},"Fil uchadi":{"ru":"Слон летает","en":"An elephant flies"},"Tosh suzadi":{"ru":"Камень плавает","en":"A stone swims"}});
